import React,{useEffect,useMemo,useState}from"react";import{CreditCard,Search,WalletCards}from"lucide-react";import{vendorAPI,formatDate,money,safeArray}from"../../services/api.js";import{useToast}from"../../components/ui/Toast.jsx";import Modal from"../../components/ui/Modal.jsx";import{CardPanel,DetailsGrid,PageHeader,StatCard,StatusPill}from"../../components/ui/PortalUI.jsx";
export default function VendorPaymentsPage(){const{showToast}=useToast();const[payments,setPayments]=useState([]);const[keyword,setKeyword]=useState("");const[selected,setSelected]=useState(null);useEffect(()=>{(async()=>{try{setPayments(safeArray(await vendorAPI.payments()))}catch(e){showToast(e.message,"error")}})()},[]);const rows=useMemo(()=>payments.filter(p=>[p.move?.job_id,p.amount,p.status].filter(Boolean).join(" ").toLowerCase().includes(keyword.toLowerCase())),[payments,keyword]);const total=payments.reduce((s,p)=>s+Number(p.amount||0),0);return <div className="page-wrap"><PageHeader icon={WalletCards} title="Payments" subtitle="Track earnings and transactions." search={keyword} onSearch={setKeyword}/><div className="stat-grid"><StatCard label="Total Earnings" value={money(total)} icon={WalletCards} tone="green"/><StatCard label="This Month" value={money(total)} icon={CreditCard} tone="blue"/><StatCard label="Pending Payout" value={money(0)} icon={CreditCard} tone="orange"/><StatCard label="Completed Jobs" value={payments.length} icon={CreditCard} tone="navy"/></div><CardPanel title="Vendor Payments"><div className="table-scroll"><table><thead><tr><th>Payment ID</th><th>Job ID</th><th>Amount</th><th>Type</th><th>Status</th><th>Date</th><th>Action</th></tr></thead><tbody>{rows.map(p=><tr key={p.id}><td><b>PAY-{p.id}</b></td><td>{p.move?.job_id||`ANQ-${p.move_request_id||"—"}`}</td><td>{money(p.amount)}</td><td>{p.payment_type||"deposit"}</td><td><StatusPill value={p.status}/></td><td>{formatDate(p.paid_at||p.created_at)}</td><td><button className="tiny-btn" onClick={()=>setSelected(p)}>View</button></td></tr>)}</tbody></table>{!rows.length?<div className="empty-state">No payments found.</div>:null}</div></CardPanel><Modal open={!!selected} title="Payment Details" onClose={()=>setSelected(null)} size="lg"><DetailsGrid rows={[["Payment ID",`PAY-${selected?.id||""}`],["Amount",money(selected?.amount)],["Status",selected?.status],["Gateway",selected?.payment_gateway],["Paid At",formatDate(selected?.paid_at||selected?.created_at)]]}/></Modal></div>}
